    description:
      "Run and troubleshoot repository code generation after detecting the generator contract. Use when schema, query, spec, or template inputs changed, or generated output may be stale.",
    repository: "matt-riley/agent-skills",
    sourceUrl:
      "https://github.com/matt-riley/agent-skills/blob/main/skills/code-generation/SKILL.md",
    rawUrl:
      "https://raw.githubusercontent.com/matt-riley/agent-skills/main/skills/code-generation/SKILL.md",
