      "https://github.com/matt-riley/agent-skills/blob/main/skills/reverse-prompt/SKILL.md",
    rawUrl:
      "https://raw.githubusercontent.com/matt-riley/agent-skills/main/skills/reverse-prompt/SKILL.md",
